class Solution:
    def answerQueries(self, nums, queries):
        s = sorted(nums)
        res = []
        for q in queries:
            total = 0
            count = 0
            for v in s:
                if total + v <= q:
                    total += v
                    count += 1
                else:
                    break
            res.append(count)
        return res

