import bisect
class Solution:
    def answerQueries(self, nums, queries):
        s = sorted(nums)
        prefix = []
        run = 0
        for v in s:
            run += v
            prefix.append(run)
        return [bisect.bisect_right(prefix, q) for q in queries]

