var answerQueries = function(nums, queries) {
    const s = nums.slice().sort((a, b) => a - b);
    const prefix = [];
    let run = 0;
    for (const v of s) { run += v; prefix.push(run); }
    const upperCount = (q) => {
        let lo = 0, hi = prefix.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (prefix[mid] <= q) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    return queries.map(upperCount);
};
